import{_ as e,a as r,b as t,c as o,d as p,e as h}from"./chunks/图六.DHvd_wWn.js";import{_ as i,o as l,c as s,ag as n}from"./chunks/framework.ETe_P6d1.js";const x=JSON.parse('{"title":"主客之间——开平侨乡建筑空间中的女性生存图景","description":"","frontmatter":{"title":"主客之间——开平侨乡建筑空间中的女性生存图景"},"headers":[],"relativePath":"reports/主客之间——开平侨乡建筑空间中的女性生存图景/陈昱希_调研报告.md","filePath":"reports/主客之间——开平侨乡建筑空间中的女性生存图景/陈昱希_调研报告.md"}'),d={name:"reports/主客之间——开平侨乡建筑空间中的女性生存图景/陈昱希_调研报告.md"};function c(_,a,m,u,b,q){return l(),s("div",null,[...a[0]||(a[0]=[n('<h1 id="主客之间——开平侨乡建筑空间中的女性生存图景" tabindex="-1">主客之间——开平侨乡建筑空间中的女性生存图景 <a class="header-anchor" href="#主客之间——开平侨乡建筑空间中的女性生存图景" aria-label="Permalink to &quot;主客之间——开平侨乡建筑空间中的女性生存图景&quot;">​</a></h1><h1 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h1><h1 id="关键词" tabindex="-1">关键词 <a class="header-anchor" href="#关键词" aria-label="Permalink to &quot;关键词&quot;">​</a></h1><hr><h1 id="一、引言-被遮蔽的另一半历史" tabindex="-1">一、引言：被遮蔽的另一半历史 <a class="header-anchor" href="#一、引言-被遮蔽的另一半历史" aria-label="Permalink to &quot;一、引言：被遮蔽的另一半历史&quot;">​</a></h1><p>开平碉楼与村落于2007年被列入《世界遗产名录》，以其独特的中西合璧建筑风格和防御功能成为岭南侨乡的文化地标。关于开平碉楼的研究，长期以来围绕华侨的跨国流动、建筑风格的中西交融、文化遗产的保护利用等议题展开，而性别视角几乎始终缺席。碉楼的主人被预设为男性华侨——“金山伯”，碉楼的故事被讲述为男性闯荡海外、衣锦还乡、建楼立业的故事。然而，开平1833座碉楼的真正日常使用者是谁？在男性长年缺席的情况下，是谁在维护这些建筑、维系这些家庭？女性在这些空间中扮演了怎样的角色？她们的生存图景又是怎样被建筑空间所塑造和表达的？</p><p>本文试图以立园、仓东村、塘口墟、赤坎古镇四个考察点为基础，从建筑学的空间维度切入，结合性别研究视角，重新审视开平侨乡建筑中的女性叙事。通过分析女性在空间建构中的被动处境与在空间使用中的主体性实践之间的张力，呈现一幅被遮蔽已久的、关于女性与建筑的复杂图景。</p><hr><h1 id="二、四个案例的空间分析-建筑维度下的女性视角" tabindex="-1">二、四个案例的空间分析：建筑维度下的女性视角 <a class="header-anchor" href="#二、四个案例的空间分析-建筑维度下的女性视角" aria-label="Permalink to &quot;二、四个案例的空间分析：建筑维度下的女性视角&quot;">​</a></h1><h3 id="一-立园-以-爱-之名——碉楼空间的男性建构与女性符号化" tabindex="-1">（一）立园：以“爱”之名——碉楼空间的男性建构与女性符号化 <a class="header-anchor" href="#一-立园-以-爱-之名——碉楼空间的男性建构与女性符号化" aria-label="Permalink to &quot;（一）立园：以“爱”之名——碉楼空间的男性建构与女性符号化&quot;">​</a></h3><p>立园是旅美华侨谢维立于1926年至1936年建造的私人园林，占地近两万平方米，是我国南方规模最大的华侨园林。园中的毓培别墅，建于1936年，由华侨方润文为纪念早逝的原配夫人谭玉英而建。从外观来看，这座四层建筑呈独特的圆柱形，顶部有拜占庭风格的穹顶和古罗马石柱，墙体采用意大利批荡工艺，内部每一层地板铺设不同图案的马赛克瓷砖，天花装饰融合了中国传统吉祥图案与西洋几何线条。这些精致的建造材料、复杂的装饰符号与考究的构造工艺，无一不体现了建造者对品质与审美的追求，也传递了浓厚的文化交融信号。</p><p>然而，当我们从空间与性别的关系来审视毓培别墅，便会发现一种耐人寻味的权力结构。有一种广泛流传的说法认为，这座四层主楼分别代表方润文先生生命中的四位女性——原配夫人与三位妻妾，每一层都寄托着一份情感。这座建筑以“爱”为名，以精美的装饰为表达方式，但其背后却是一种典型的男性主导的空间建构：女性被物化为建筑符号，她们的名字被嵌入楼层数字的隐喻之中，她们的存在被凝固在瓷砖、彩窗和家具之中，而她们自己对于空间的需求、对于建筑的想象、对于“家”的定义，从未被纳入建造决策。</p><p>立园的空间类型是典型的“博物馆化的遗产呈现”——它被完整地保护下来，作为一种文化展品向参观者开放。但在这个被保护的空间中，我们看到的更多是男性建造者的审美意志和情感投射，女性的主体性始终处于缺席状态。这种“被书写”的命运，恰恰是侨乡建筑中女性处境的缩影——她们是碉楼中被展示的对象，却不是空间的主人。</p><p><img src="'+e+'" alt="图1"></p><h3 id="二-仓东村-从-空心村-到活态遗产——女性在社区参与中的空间重塑" tabindex="-1">（二）仓东村：从“空心村”到活态遗产——女性在社区参与中的空间重塑 <a class="header-anchor" href="#二-仓东村-从-空心村-到活态遗产——女性在社区参与中的空间重塑" aria-label="Permalink to &quot;（二）仓东村：从“空心村”到活态遗产——女性在社区参与中的空间重塑&quot;">​</a></h3><p>仓东村是开平塘口镇的一个典型华侨村落。上世纪初，大批华侨返乡，在此兴建了数十栋融合中西建筑风格的民居、祠堂和碉楼。这些建筑在材料上大量使用了华侨从海外运回的“红毛泥”（水泥），在装饰符号上既有岭南传统的灰雕工艺，又融入了巴洛克风格的山花图案和火车、轮船等新式题材。建筑的功能布局充分体现了侨乡社会的特点——集居住、防御、祭祀于一体，环境关系上形成了以祠堂为核心、民居和碉楼错落分布的村落格局。</p><p>然而，从上世纪80年代起，仓东村的村民纷纷移民至海外或国内其他城市，村落日渐凋敝，仅剩数户老人和儿童居住。大量建筑空置，昔日繁华的华侨村落变成了“空心村”。在这一背景下，五邑大学广东侨乡文化研究院教授谭金花——一位从开平走出去的女性学者——发起了“仓东计划”，以修旧如旧的建筑修复、社区共建共治和国际交流游学等方式，试图唤醒沉睡的古村，保护当地传统文化。</p><p>仓东村的空间复兴，与一位女性学者的身体力行密切相关。谭金花从小在开平长大，碉楼是她儿时的记忆。她的曾祖父1900年赴美谋生，91岁客死异乡，至死未能回乡。这段家族史驱使她远赴美国研读华侨史，回国后成为开平碉楼申报世界文化遗产的技术指导专家，负责英文申报文本和规划文本的撰写工作。从家族中留守女性的悲情叙事，到一位现代女性学者主导文化遗产保护，仓东村的故事本身就是侨乡女性代际命运变迁的鲜活写照。</p><p>更重要的是，仓东计划的实践模式在空间活化中体现了鲜明的“女性特质”——它不追求大拆大建的改造速度，而是强调社区参与、代际传承和国际交流。这种柔性的、注重关系的保护方式，与碉楼建设中那种以防御功能为核心的“男性气质”形成了有趣的对照。女性在仓东村的空间重塑中，不再是被动的使用者，而成为了积极的创造者。</p><p><img src="'+r+'" alt="图2"></p><h3 id="三-塘口墟与赤坎古镇-公共空间中的性别边界" tabindex="-1">（三）塘口墟与赤坎古镇：公共空间中的性别边界 <a class="header-anchor" href="#三-塘口墟与赤坎古镇-公共空间中的性别边界" aria-label="Permalink to &quot;（三）塘口墟与赤坎古镇：公共空间中的性别边界&quot;">​</a></h3><p>塘口墟和赤坎古镇是开平地区重要的侨乡商贸空间。塘口墟始建于清光绪初年，逢五日、十日为墟期，是当地最大的墟集。赤坎古镇则以其绵延数百米的骑楼街区著称，这些骑楼建筑在功能布局上形成了“下店上居”的模式——首层为商业铺面，上层为居住空间。在建造材料上，骑楼广泛使用了从海外进口的钢筋、水泥和彩色玻璃，在装饰符号上融合了巴洛克山花、罗马柱式与岭南灰雕工艺。</p><p>然而，从性别视角审视这些公共商业空间，我们会发现一个隐蔽的结构性问题：侨墟空间的使用权在历史上是高度性别化的。清代的开平社会，乡村女性虽然在一定程度上参与了市场活动——有研究表明，由于男性出洋谋生，女性对乡村社会市场的发育及其家庭生活的稳定做出了显著贡献——但她们的参与主要局限在与家庭生计直接相关的领域，而真正的商业决策、产权归属和公共事务，仍然由男性掌控。</p><p>赤坎古镇的整体性旅游开发——将整片骑楼街区改造为文化旅游景区——在提升空间品质的同时，也引发了一个新的问题：在商业化的叙事中，谁的故事被讲述？漫步赤坎的骑楼老街，游客看到的是华侨创业的传奇、中西文化的交融、百年商埠的繁华。但在这些宏大叙事的背后，那些在骑楼二楼日夜操劳、维持家庭运转的女性——她们的故事依然很少有人问津。</p><p><img src="'+t+'" alt="图3"></p><h3 id="四-碉楼与女性空间-四个观察维度的整合分析" tabindex="-1">（四）碉楼与女性空间：四个观察维度的整合分析 <a class="header-anchor" href="#四-碉楼与女性空间-四个观察维度的整合分析" aria-label="Permalink to &quot;（四）碉楼与女性空间：四个观察维度的整合分析&quot;">​</a></h3><p>从空间类型与形态来看，开平碉楼以多层塔楼为主体，辅以庭院和附属建筑。这种空间布局的初衷是防御——高耸的塔身、狭小的窗户、顶部突出的角堡和射击孔，都是为抵御匪盗而设计的。防御功能的需求决定了碉楼空间的封闭性和内向性，而这一特征对居住其中的女性产生了双重影响：一方面，封闭的空间进一步限制了女性的活动范围，强化了“女主内”的传统性别分工；另一方面，在男性长年缺席的情况下，这座封闭的堡垒实际上成为了女性可以自主管理的空间领地。</p><p>从建造材料与构造来看，碉楼大量使用海外运回的水泥、钢筋和进口瓷砖，这些材料本身就是华侨跨国流动的物质见证。值得注意的是，这些建筑材料的选择和使用完全由男性决定——从海外赚取侨汇的男性华侨决定建楼的规格、选定材料的种类、确定装饰的风格，而女性在这些决策中几乎没有发言权。女性的物质存在，更多体现在碉楼内部的日常用品中——厨房的炊具、卧室的家具、储藏的粮食——这些“软”的物质文化构成了女性空间的物质基础，却往往被建筑研究所忽视。</p><p>从功能布局与使用方式来看，碉楼的日常运作高度依赖女性的劳动。男性华侨常年在海外谋生，有的数年不归，甚至客死异乡。留守的女性不仅要照顾老人和孩子、管理家中的田产，还要负责碉楼的日常维护——这在当时的条件下是极为繁重的体力劳动。可以说，女性是碉楼的实际运营者，但她们的使用方式从未被纳入建筑设计的前期考量。</p><p>从环境关系与场所精神来看，碉楼所处的环境——稻田、竹林、池塘、村落——构成了侨乡女性主要的活动空间。她们的劳动和社交大多发生在这个半径有限的乡土空间中。而对于远在海外的丈夫，这个空间则承载着复杂的“场所精神”——它是乡愁的寄托、是归根的方向、是建楼的全部意义所在。于是，一个深刻的悖论浮现了：碉楼对于男性而言是符号性的存在，是他们海外奋斗的目标和归宿；而对于女性而言，碉楼是日常性的存在，是她们日复一日生活的具体场所。符号与日常之间的断裂，恰恰揭示了侨乡建筑空间中性别体验的根本差异。</p><p><img src="'+o+'" alt="图4"></p><hr><h1 id="三、女性在侨乡建筑中的双重角色-使用者与维系者" tabindex="-1">三、女性在侨乡建筑中的双重角色：使用者与维系者 <a class="header-anchor" href="#三、女性在侨乡建筑中的双重角色-使用者与维系者" aria-label="Permalink to &quot;三、女性在侨乡建筑中的双重角色：使用者与维系者&quot;">​</a></h1><h3 id="一-被空间规训的客体-厨房、祠堂与公共空间的性别分工" tabindex="-1">（一）被空间规训的客体：厨房、祠堂与公共空间的性别分工 <a class="header-anchor" href="#一-被空间规训的客体-厨房、祠堂与公共空间的性别分工" aria-label="Permalink to &quot;（一）被空间规训的客体：厨房、祠堂与公共空间的性别分工&quot;">​</a></h3><p>在中国传统民居的空间组织中，女性的活动范围长期受到礼教的严格限制。有研究者指出，中国传统民居中女性所生活的环境空间，其形成背景与中国封建礼制、性别角色等社会问题密切相关，等级制的空间结构在很大程度上规训了女性的行为。这一分析同样适用于开平侨乡的建筑空间。</p><p>碉楼内部的厨房，是侨乡女性日常劳动的核心场所。开平碉楼的厨房通常设在首层或地下层，空间狭小、采光不足，与楼上宽敞明亮的厅堂和卧室形成鲜明对比。这种空间安排本身即是一种无声的等级表达——女性的劳动空间被置于建筑的边缘和底层。此外，祠堂作为宗族文化的核心空间，女性在其中也面临着严格的规约。传统宗族社会中，女性不仅不能参与祠堂内的祭祀仪式，甚至在祠堂建筑的动工、上梁等关键环节中也被禁止在场——这种空间禁忌折射出宗法制度下女性在建筑神圣空间中“被污染”的象征定位。</p><p>塘口墟等侨墟公共空间同样存在隐性的性别边界。女性可以出现在墟市中进行买卖活动，但墟市的经营权和产权归属几乎全部掌握在男性手中。女性在公共空间中的存在是“功能性的”——她们的出现是为了完成特定的家务或交易目的，而非以独立主体的身份参与公共生活。</p><p><img src="'+p+'" alt="图5"></p><h3 id="二-作为空间主体的实践-日常管理与精神守护" tabindex="-1">（二）作为空间主体的实践：日常管理与精神守护 <a class="header-anchor" href="#二-作为空间主体的实践-日常管理与精神守护" aria-label="Permalink to &quot;（二）作为空间主体的实践：日常管理与精神守护&quot;">​</a></h3><p>然而，如果仅仅将侨乡女性视为被规训的客体，就会遮蔽她们在建筑空间中真实的主体性实践。事实上，正是女性的日常劳动和精神守护，赋予了碉楼以“家”的温度和意义。</p><p>这种主体性首先体现为碉楼的日常管理与维护。男性华侨常年在海外，有的甚至终身未归。85岁的关老太太是目前少有的仍然住在碉楼里的开平人，从嫁到谢家起，她已在碉楼里生活了60多年。像关老太太这样的留守女性，是碉楼真正的日常管理者——她们打扫楼宇、修缮损坏的部件、接待回乡的族人、守护家族的记忆。当碉楼的男性建造者远在天边时，是女性日复一日的劳动让这些建筑保持了生活的温度。</p><p>这种主体性还体现为精神层面的守护。如果说金山伯是碉楼的缔造者，那么金山伯的女人则是碉楼的守护者。当男人们长期漂泊在异国他乡时，他们背后的女人们就义不容辞地撑起了家庭的半边天，以现代人无法想象的坚强毅力等待丈夫归来。有一些金山伯的女人从未见过丈夫一面，就把自己的一生套上了有名无实的枷锁。与其说碉楼象征着身份、地位和财富，还不如说它象征着艰难、磨练和执着。这种守护不是被动的等待，而是一种积极的承担——她们守护的不只是一座建筑，更是一个家庭在动荡时代中的生存和延续。</p><p><img src="'+h+'" alt="图6"></p><h3 id="三-侨汇经济中的女性角色-隐形的经济运作者" tabindex="-1">（三）侨汇经济中的女性角色：隐形的经济运作者 <a class="header-anchor" href="#三-侨汇经济中的女性角色-隐形的经济运作者" aria-label="Permalink to &quot;（三）侨汇经济中的女性角色：隐形的经济运作者&quot;">​</a></h3><p>华侨研究长期以来将侨汇视为男性劳工的成果，而忽视了女性在侨汇管理和使用中的核心作用。事实上，当男性华侨从海外寄回钱款时，真正负责收管、分配和使用这些资金的是留守的妻子。她们需要用这些钱维持家庭日常开销、购置田产、修缮房屋、抚养子女、接济亲戚——这是一套复杂的经济管理工作。</p><p>有研究表明，清代开平乡村社会的市场化倾向较为明显，女性与乡村社会区域市场发育有很大关联。由于男性出洋谋生，女性对乡村社会市场的发育及其家庭生活的稳定做出了显著贡献。这意味着，侨乡女性不仅仅是“等待者”或“留守者”，她们实际上承担了大量的经济活动——从家庭内部的收支管理到参与乡村市场的商品交易，她们在经济领域中发挥着不可替代的作用。</p><p>然而，这种经济贡献在碉楼的物质空间中几乎没有得到任何表达。碉楼的匾额上刻的是男性的名字，碉楼的装饰符号讲述的是男性海外闯荡的故事，碉楼的建造铭文记录的是男性捐资者的功绩。女性的经济贡献是“隐形的”——它存在于侨汇的账本中、市场的交易中、日常的开销中，却从未在建筑的物质形态中获得象征性的表达。这一现象深刻揭示了侨乡建筑空间叙事中的性别偏斜：男性通过建筑获得不朽的物质纪念，而女性的贡献则随着她们的离世而消散。</p><hr><h1 id="四、当代转型-从-被书写-到-书写自己" tabindex="-1">四、当代转型：从“被书写”到“书写自己” <a class="header-anchor" href="#四、当代转型-从-被书写-到-书写自己" aria-label="Permalink to &quot;四、当代转型：从“被书写”到“书写自己”&quot;">​</a></h1><h3 id="一-仓东计划与女性的遗产保护实践" tabindex="-1">（一）仓东计划与女性的遗产保护实践 <a class="header-anchor" href="#一-仓东计划与女性的遗产保护实践" aria-label="Permalink to &quot;（一）仓东计划与女性的遗产保护实践&quot;">​</a></h3><p>仓东计划的成功，本身就是侨乡女性从“被书写”走向“书写自己”的典型案例。谭金花教授——这位从开平走出去的女性学者——凭借对家乡碉楼的深厚情感和扎实的专业素养，将一个濒临消亡的古村落变成了国际知名的遗产保护典范。2015年，仓东计划获得联合国教科文组织亚太区文化遗产保护优秀奖；2021年，被联合国教科文组织亚太遗产中心评为“全球世界遗产教育创新优秀推荐案例”之一。</p><p>谭金花的故事还具有更深层的家族史意义。她的曾祖父1900年赴美谋生，至死未能回乡。曾祖母——一位典型的侨乡留守女性——独自抚养孩子，靠丈夫寄回的微薄侨汇维持生计，在无尽的等待中度过了大半生。两代女性，相同的侨乡血脉，截然不同的命运：曾祖母是被历史裹挟的“等待者”，而谭金花是主动介入历史的“书写者”。这种代际命运的变迁，本身就是侨乡女性地位变迁的最生动注解。</p><h3 id="二-从留守到参与-女性与建筑空间关系的历史演变" tabindex="-1">（二）从留守到参与：女性与建筑空间关系的历史演变 <a class="header-anchor" href="#二-从留守到参与-女性与建筑空间关系的历史演变" aria-label="Permalink to &quot;（二）从留守到参与：女性与建筑空间关系的历史演变&quot;">​</a></h3><p>纵观开平侨乡百余年来的历史变迁，女性与建筑空间的关系经历了深刻的变化。在碉楼建造的高峰期（19世纪末至20世纪30年代），女性几乎完全被排除在建筑决策之外，她们的存在更多体现为建筑内部的使用者和维护者。新中国成立后，随着传统宗族制度的瓦解和女性受教育程度的提高，女性开始走出家庭空间，进入更广阔的社会空间。到了当代，像谭金花这样的女性学者已经能够在文化遗产保护这一专业领域发出自己的声音，她们不再是建筑的被动使用者，而成为了建筑文化意义的主动阐释者和传播者。</p><p>这种转变不仅仅是个人命运的转变，更是社会结构和性别观念变化的反映。建筑空间的生产从来不只是物质性的工程，它同时也是社会关系和权力结构的物化表达。当女性开始在建筑领域获得话语权时，她们不仅改变了自己的命运，也在重新定义建筑与社会的关系。</p><hr><h1 id="五、结语" tabindex="-1">五、结语 <a class="header-anchor" href="#五、结语" aria-label="Permalink to &quot;五、结语&quot;">​</a></h1><p>开平碉楼与村落是一本用砖石水泥写就的侨乡历史。翻阅这本厚重的书，我们读到的不仅是华侨闯荡海外的传奇，不仅是中西文化交融的精彩篇章，还有那些被长期遮蔽的、属于女性的故事。她们在碉楼的厨房中劳作，在祠堂的边缘守望，在侨墟的骑楼中营生，在漫长的等待中维持着家庭的运转。她们既是建筑空间中被规训的客体，也是建筑使用中最坚韧的主体。她们的名字很少刻在匾额上，但她们的生命却真实地烙印在每一块砖石、每一扇窗棂、每一寸马赛克瓷砖之中。</p><p>从立园毓培别墅中被符号化的女性形象，到仓东村中主导遗产保护的女性学者，侨乡建筑中的女性叙事呈现出一条清晰的演进轨迹：从“被书写”到“书写自己”，从空间的被动使用者到空间的主动塑造者。这条轨迹既是侨乡女性地位变迁的缩影，也是建筑空间性别政治的一面镜子。</p><p>当我们今天行走在开平的碉楼村落之间，或许应该多问一个问题：除了建造者，还有谁曾在这里生活？她们的故事值得被讲述吗？建筑空间中的性别维度，从来不是可有可无的补充——它是理解人与空间关系的核心维度之一，缺了这一维，我们的认知就不完整。正如一位研究者所言，由两性共同构成的移民及华侨华人史如果缺少社会性别视角，对复杂多元历史的阐述都会显得单调与不足。这句话，同样适用于侨乡建筑的研究。</p><hr><h1 id="参考文献" tabindex="-1">参考文献 <a class="header-anchor" href="#参考文献" aria-label="Permalink to &quot;参考文献&quot;">​</a></h1><p>[1] 谭金花.开平碉楼与村落的建筑装饰研究[M].北京：中国华侨出版社，2013. [2] 刘正刚，魏珂.清代侨乡女性生活探析——以开平为例[J].五邑大学学报（社会科学版），2006(04). [3] 沈惠芬.社会性别与历史书写：20世纪上半叶福建移民家眷生命史研究[M]. [4] 弱女孤身赴美揭开五邑碉楼之谜[N].新浪新闻，2005-06-07. [5] 荒村来了个女教授 五年捧回国际大奖[N].广州日报，2016-03-12. [6] 昔日情怀|一封来自1921年的情信[EB/OL].开平旅游网. [7] 浅析中国传统文化影响下的女性空间[J].艺术与设计（理论），2009(08). [8] 故园依旧在 主人几时归[N].南方都市报，2002-08-26.</p>',63)])])}const k=i(d,[["render",c]]);export{x as __pageData,k as default};
